// --- PROJECT 1: "SOLAR PANEL" RELATIONSHIPS ---

MATCH (p:Person {name: 'Alice'}), (proj:Project {title: 'Solar Panel'})
    MERGE (p)-[:WORK_ON {role: 'Project Member'}]->(proj);
MATCH (p:Person {name: 'Alice'}), (d:Domain {name: 'Renewable Energy'})
    MERGE (p)-[:EXPERT_AT]->(d);
MATCH (p:Person {name: 'Alice'}), (dept:Department {name: 'Engineering'})
    MERGE (p)-[r:FIELD_IN]->(dept)
    SET r.startDate = date('2010-05-01'), r.endDate = null; 
MATCH (p:Person {name: 'David'}), (proj:Project {title: 'Solar Panel'})
    MERGE (p)-[:WORK_ON {role: 'Project Member'}]->(proj);
