    MERGE (p)-[:EXPERT_AT]->(d);
MATCH (s:Student {name: 'Bob'}), (proj:Project {title: 'Solar Panel'})
    MERGE (s)-[:ASSIST_ON {
        responsibility: 'Data Collection',
        maximumWorkingRatePerHours: 20,
        ratePerHours: 18.50,
        startDate: date('2023-06-01'),
        endDate: date('2024-06-01')
    }]->(proj);
