    MERGE (s)-[r:BELONG_TO]->(dept) 
    SET r.startDate = date('2022-08-20'), r.endDate = date('2026-05-15');


MATCH (d:Domain {name: 'Renewable Energy'}), (proj:Project {title: 'Solar Panel'})
    MERGE (d)-[:RESEARCH_AT]->(proj);
MATCH (d:Domain {name: 'Data Science'}), (proj:Project {title: 'Solar Panel'})
    MERGE (d)-[:RESEARCH_AT]->(proj);
MATCH (k:Keyword {name: 'Photovoltaics'}), (proj:Project {title: 'Solar Panel'})
    MERGE (k)-[:SEARCH_ON]->(proj);
MATCH (k:Keyword {name: 'Energy Storage'}), (proj:Project {title: 'Solar Panel'}) 
    MERGE (k)-[:SEARCH_ON]->(proj);
