    MERGE (c)-[:IS_CATEGORIZED]->(proj); 


MATCH (proj:Project {title: 'Solar Panel'}), (don:Donate {totalAmount: 500000})
    MERGE (don)-[:DONATE_TO]->(proj); 
MATCH (dr:Donor {name: 'Global Philanthropy Inc.'}), (don:Donate {totalAmount: 500000})
    MERGE (dr)-[:CONTRIBUTE_TO]->(don); 
MATCH (don:Donate {totalAmount: 500000}), (inst:Installment {installmentId: 'I-001'}) 
    MERGE (don)-[r:IS_DIVIDED {
        amount: 100000,
        date: date('2023-02-01'),
        percent: 20
    }]->(inst);
